```class Solution {
public:
    long long repairCars(vector<int>& ranks, int cars) {
        long long res = LLONG_MAX;
        for (int r : ranks) {
            long long time = 0;
            int left = 0, right = cars;
            while (left <= right) {
                int mid = left + (right - left) / 2;
                time = r * mid * mid;
                if (time < cars) {
                    left = mid + 1;
                } else {
                    right = mid - 1;
                    res = min(res, time);
                }
            }
        }
        return res;
    }
};```
